mapper.select:
select *,required_class_hour as requiredMinutes
from people_enterprise
left join  (
select a.employee_id_number as employee_id_number,sum(a.material_learn_length) as learningMinutes
from (
select distinct employee_id_number,material_id,material_learn_length
from employee_train
where operate_time < #{yearEnd} and operate_time > #{yearStart} and record_status = 1
) as a
group by a.employee_id_number
) as b on identity_number = b.employee_id_number



            (learningMinutes is null or learningMinutes = 0 or learningMinutes = ' ')


            learningMinutes < required_class_hour and learningMinutes != 0


            learningMinutes >= required_class_hour



        and enterprise_area_id in

            #{town}



        and ${searchParam.townId} in

            #{town}

        and enterprise_area_id = #{searchParam.townId}

     #{searchParam.userType}
        and enterprise_area_id = #{searchParam.townId}


        and (
        enterprise_name like concat('%',#{searchParam.multiParam},'%') or
        people_name like concat('%',#{searchParam.multiParam},'%') or
        identity_number like concat('%',#{searchParam.multiParam},'%')
        )


        and social_credit_code = #{searchParam.creditCode}


        and industry_type_person = #{searchParam.industryType}


        and work_type_name = #{searchParam.workType}

select sum(a.material_learn_length) as totalTime
from (
select distinct (material_id),material_learn_length
from employee_train
where employee_id_number = #{idNumber} and operation_datetime < #{yearEnd} and operation_datetime > #{yearStart}

    and course_id in

        #{courseId}


) as a

select sum(material_learn_length) as totalCourseTime
from employee_train
where employee_id_number = #{idNumber} and course_id = #{courseId}

    and material_id in

        #{materialId}
